# startup_guard.py — fail fast if running outside expected venv
import sys, os

def assert_venv(expected_suffix: str = ".venv") -> None:
    """Raise RuntimeError if the process is not inside a virtual environment."""
    if sys.prefix == sys.base_prefix:
        raise RuntimeError(
            "This service must run inside a virtual environment. "
            "Activate with: source .venv/bin/activate"
        )
    if not sys.prefix.endswith(expected_suffix):
        raise RuntimeError(
            f"Unexpected venv active: {sys.prefix!r}. "
            f"Expected path ending in {expected_suffix!r}."
        )

# Call at module load time so the error surfaces before any LLM calls
assert_venv()
